// ============================================================
// MERGE REPORT DATA - n8n Code Node (Multi-Campaign)
// Runs once for all items, outputs one item per matched campaign
// ============================================================
const config = $('Workflow Configuration').first().json;
const clientName = config.clientName || 'Unknown Client';
const startDate = config.startDate || '';
const endDate = config.endDate || '';
const campaignContext = config.campaignContext || '';

// Index analytics by campaign_id
const analyticsMap = {};
try {
  $('Get Campaign Analytics').all().forEach(item => {
    const id = item.json.campaign_id;
    if (id) analyticsMap[id] = item.json;
  });
} catch(e) {}

// Index matched campaign data by id
const campaignDataMap = {};
try {
  $('Get matched campaign data').all().forEach(item => {
    const id = item.json.id;
    if (id) campaignDataMap[id] = item.json;
  });
} catch(e) {}

// Index leads by campaign_id
const leadsMap = {};
try {
  $('Get all leads').all().forEach(item => {
    const leads = item.json.items || [];
    leads.forEach(lead => {
      const cid = lead.campaign;
      if (!cid) return;
      if (!leadsMap[cid]) leadsMap[cid] = [];
      leadsMap[cid].push(lead);
    });
  });
} catch(e) {}

// Accounts are shared - get all once
let allAccounts = [];
try {
  const rawAccounts = $('Get all accounts').first().json;
  allAccounts = rawAccounts.items || [];
} catch(e) {}

// Index replies by campaign_id
const repliesMap = {};
try {
  $('Get Campaign Replies').all().forEach(item => {
    const emails = item.json.emails || item.json.items || item.json.data || [];
    emails.forEach(e => {
      const cid = e.campaign_id || e.campaign;
      if (!cid) return;
      if (!repliesMap[cid]) repliesMap[cid] = [];
      repliesMap[cid].push(e);
    });
  });
} catch(e) {}

// Index lifetime analytics by campaign_id
const lifetimeMap = {};
try {
  $('Get Lifetime Campaign Analytics').all().forEach(item => {
    const id = item.json.campaign_id;
    if (id) lifetimeMap[id] = item.json;
  });
} catch(e) {}

// Get all matched campaigns
const matchedCampaigns = $('Match Instantly Campaign Name - Exist or not').all()
  .filter(item => item.json.matched === true);

const results = [];

for (const matchItem of matchedCampaigns) {
  const matchData = matchItem.json;
  const campaignId = matchData.matchedCampaignId;
  const targetCampaignName = matchData.targetCampaignName;

  const campaignData = campaignDataMap[campaignId] || matchData.matchedCampaign || {};
  const analyticsData = analyticsMap[campaignId] || {};
  const leads = leadsMap[campaignId] || [];
  const replies = repliesMap[campaignId] || [];

  const requestContext = { clientName, startDate, endDate, campaignContext, targetCampaignName };

const leadsAnalysis = { totalLeads: leads.length, byStatus: {}, byJobTitle: {}, byLocation: {}, byCompany: {}, withReplies: [] };
leads.forEach(lead => {
  const status = lead.status;
  leadsAnalysis.byStatus[status] = (leadsAnalysis.byStatus[status] || 0) + 1;
  const jobTitle = lead.payload?.jobTitle || 'Unknown';
  leadsAnalysis.byJobTitle[jobTitle] = (leadsAnalysis.byJobTitle[jobTitle] || 0) + 1;
  const location = lead.payload?.location || 'Unknown';
  const locationParts = location.split(',');
  const region = locationParts[locationParts.length - 1]?.trim() || 'Unknown';
  leadsAnalysis.byLocation[region] = (leadsAnalysis.byLocation[region] || 0) + 1;
  const company = lead.company_name || 'Unknown';
  leadsAnalysis.byCompany[company] = (leadsAnalysis.byCompany[company] || 0) + 1;
  if (lead.email_reply_count > 0) {
    leadsAnalysis.withReplies.push({ email: lead.email, name: `${lead.first_name} ${lead.last_name}`, company: lead.company_name, jobTitle: lead.payload?.jobTitle, replyCount: lead.email_reply_count });
  }
});

const accounts = allAccounts;
const campaignEmailList = campaignData.email_list || [];
const campaignAccounts = accounts.filter(acc => campaignEmailList.includes(acc.email));
const accountsAnalysis = { totalInCampaign: campaignAccounts.length, totalAvailable: accounts.length, averageWarmupScore: 0, byStatus: {}, healthySenders: [], problemSenders: [] };
let warmupScoreSum = 0, warmupScoreCount = 0;
campaignAccounts.forEach(account => {
  if (account.stat_warmup_score !== undefined) { warmupScoreSum += account.stat_warmup_score; warmupScoreCount++; }
  const status = account.status === 1 ? 'Active' : 'Inactive';
  accountsAnalysis.byStatus[status] = (accountsAnalysis.byStatus[status] || 0) + 1;
  const senderInfo = { email: account.email, name: `${account.first_name} ${account.last_name}`, warmupScore: account.stat_warmup_score || 0, status: account.status, dailyLimit: account.daily_limit };
  if (account.stat_warmup_score >= 80 && account.status === 1) { accountsAnalysis.healthySenders.push(senderInfo); } else { accountsAnalysis.problemSenders.push(senderInfo); }
});
accountsAnalysis.averageWarmupScore = warmupScoreCount > 0 ? Math.round(warmupScoreSum / warmupScoreCount) : 0;

const campaignConfig = { name: campaignData.name, id: campaignData.id, status: campaignData.status, statusText: ['Draft','Active','Paused','Completed'][campaignData.status] || 'Unknown', createdAt: campaignData.timestamp_created, sequences: campaignData.sequences, senderCount: campaignData.email_list?.length || 0, openTracking: campaignData.open_tracking, linkTracking: campaignData.link_tracking };

const analytics = analyticsData;
const calculatedMetrics = {
  replyRate: analytics.emails_sent_count > 0 ? ((analytics.reply_count_unique / analytics.emails_sent_count) * 100).toFixed(2) : 0,
  bounceRate: analytics.emails_sent_count > 0 ? ((analytics.bounced_count / analytics.emails_sent_count) * 100).toFixed(2) : 0,
  autoReplyRate: analytics.emails_sent_count > 0 ? ((analytics.reply_count_automatic / analytics.emails_sent_count) * 100).toFixed(2) : 0,
  emailsPerLead: analytics.leads_count > 0 ? (analytics.emails_sent_count / analytics.leads_count).toFixed(2) : 0
};

const reportData = { requestContext, campaignConfig, analytics: { ...analytics, calculated: calculatedMetrics }, leadsAnalysis: { totalLeads: leadsAnalysis.totalLeads, leadsWithReplies: leadsAnalysis.withReplies }, accountsAnalysis, generatedAt: new Date().toISOString() };

let replyHighlights = [];
try {
  const emails = replies;
  const startTs = requestContext.startDate ? new Date(requestContext.startDate).getTime() : 0;
  const endTs = requestContext.endDate ? new Date(requestContext.endDate).getTime() + 86400000 : Infinity;
  const filtered = emails.filter(e => { const ts = new Date(e.timestamp_email || e.timestamp_created || e.created_at || 0).getTime(); return ts >= startTs && ts <= endTs; });
  replyHighlights = filtered.map(e => ({ from: e.from_address_email || e.from_address || e.from || '', subject: e.subject || '', body: (e.body?.text || e.body_text || e.text_body || e.snippet || '').slice(0, 1500), timestamp: e.timestamp || e.timestamp_created || e.created_at || '' }));
} catch(err) { replyHighlights = []; }
reportData.replyHighlights = replyHighlights;

  results.push({ json: { reportData, reportDataString: JSON.stringify(reportData, null, 2) } });
}

return results;

const form = $items('Workflow Configuration')?.[0]?.json ?? {};
const targetsRaw = form.instantlyCampaignNames ?? [];
const targets = (Array.isArray(targetsRaw) ? targetsRaw : [targetsRaw]).map(t => (t == null ? '' : String(t)).trim()).filter(Boolean);
const campaigns = $json.items ?? $json.data ?? (Array.isArray($json) ? $json : []);
const norm = (s) => (s == null ? '' : String(s)).toLowerCase().replace(/[^a-z0-9]+/g, '').trim();
const byNorm = new Map();
for (const c of campaigns) { const n = c?.name ?? c?.campaign_name ?? ''; if (n) byNorm.set(norm(n), c); }
const results = [];
for (const target of targets) {
  const targetNorm = norm(target);
  let matched = byNorm.get(targetNorm) ?? null;
  if (!matched) { for (const [n, c] of byNorm.entries()) { if (n.includes(targetNorm) || targetNorm.includes(n)) { matched = c; break; } } }
  results.push({ json: { targetCampaignName: target, matched: !!matched, matchedCampaignName: matched?.name ?? matched?.campaign_name ?? null, matchedCampaignId: matched?.id ?? null, matchedCampaign: matched ?? null } });
}
if (results.length === 0) { results.push({ json: { targetCampaignName: null, matched: false, matchedCampaignName: null, matchedCampaignId: null, matchedCampaign: null, note: 'No Instantly campaigns were selected in the form.' } }); }
return results;

const config = $('Workflow Configuration').first().json;
const targetsRaw = config.heyReachCampaignNames ?? [];
const targets = (Array.isArray(targetsRaw) ? targetsRaw : [targetsRaw]).map(t => (t == null ? '' : String(t)).trim()).filter(Boolean);
const campaigns = $json.items ?? $json.data ?? (Array.isArray($json) ? $json : []);
const norm = (s) => (s == null ? '' : String(s)).toLowerCase().replace(/[^a-z0-9]+/g, '').trim();
const byNorm = new Map();
for (const c of campaigns) { const n = c?.name ?? c?.campaign_name ?? c?.title ?? ''; if (n) byNorm.set(norm(n), c); }
const results = [];
for (const target of targets) {
  const targetNorm = norm(target);
  let matched = byNorm.get(targetNorm) ?? null;
  if (!matched) { for (const [n, c] of byNorm.entries()) { if (n.includes(targetNorm) || targetNorm.includes(n)) { matched = c; break; } } }
  results.push({ json: { targetCampaignName: target, matched: !!matched, matchedCampaignName: matched?.name ?? matched?.campaign_name ?? matched?.title ?? null, matchedCampaignId: matched?.id ?? null, matchedCampaign: matched ?? null } });
}
if (results.length === 0) { results.push({ json: { targetCampaignName: null, matched: false, matchedCampaignName: null, matchedCampaignId: null, matchedCampaign: null, note: 'No HeyReach campaigns were selected in the form.' } }); }
return results;

// ============================================================
// HEYREACH MERGE REPORT DATA (Multi-Campaign)
// Runs once for all items, outputs one item per matched campaign
// ============================================================
const config = $('Workflow Configuration').first().json;

// Index campaign data by campaign id
const campaignDataMap = {};
try {
  $('Retrieve found campaign data').all().forEach(item => {
    const id = item.json.id;
    if (id) campaignDataMap[id] = item.json;
  });
} catch(e) {}

// Index stats by campaign id
const statsMap = {};
try {
  $('Retrieve overall statistics for found campaign').all().forEach(item => {
    // stats node returns overallStats — find which campaign this belongs to via item context
    // Store by index since stats don't have campaign_id directly
    statsMap[item.json._campaignId || Object.keys(statsMap).length] = item.json;
  });
} catch(e) {}

// Get LinkedIn accounts (shared)
let accountsData = [];
try {
  const rawAccounts = $('Retrieve all LinkedIn accounts').first().json;
  accountsData = rawAccounts.items || (Array.isArray(rawAccounts) ? rawAccounts : []);
} catch(e) {}

// Index inbox messages by campaign id
const inboxMap = {};
try {
  $('Retrieve inbox messages for found campaign').all().forEach(item => {
    const msgs = item.json.items || [];
    msgs.forEach(msg => {
      const cid = msg.campaignId || msg.campaign_id;
      if (!cid) return;
      if (!inboxMap[cid]) inboxMap[cid] = [];
      inboxMap[cid].push(msg);
    });
  });
} catch(e) {}

// Get all matched HeyReach campaigns
const matchedCampaigns = $('Match Heyreach Campaign Name - Exist or not').all()
  .filter(item => item.json.matched === true);

const results = [];

for (let idx = 0; idx < matchedCampaigns.length; idx++) {
  const matchData = matchedCampaigns[idx].json;
  const campaignId = matchData.matchedCampaignId;

  const requestContext = {
    clientName: config.clientName,
    campaignContext: config.campaignContext,
    startDate: config.startDate,
    endDate: config.endDate,
    targetCampaignName: matchData.targetCampaignName,
    platformName: 'HeyReach'
  };

  let campaignData = campaignDataMap[campaignId] || matchData.matchedCampaign || matchData;

  // Stats: try by campaignId match, fall back to index
  let statsData = { overallStats: {}, byDayStats: {} };
  try {
    const allStats = $('Retrieve overall statistics for found campaign').all();
    if (allStats[idx]) statsData = allStats[idx].json;
  } catch(e) {}

  const inboxData = inboxMap[campaignId] || [];

const campaignConfig = { id: campaignData.id || matchData.matchedCampaignId, name: campaignData.name || matchData.matchedCampaignName, status: campaignData.status || 'Unknown', creationTime: campaignData.creationTime, senderAccountIds: campaignData.campaignAccountIds || [], senderCount: (campaignData.campaignAccountIds || []).length, progressStats: campaignData.progressStats || { totalUsers: 0, totalUsersInProgress: 0, totalUsersPending: 0, totalUsersFinished: 0, totalUsersFailed: 0, totalUsersManuallyStopped: 0, totalUsersExcluded: 0 } };

const overallStats = statsData.overallStats || {};
const analytics = { connectionsSent: overallStats.connectionsSent || 0, connectionsAccepted: overallStats.connectionsAccepted || 0, profileViews: overallStats.profileViews || 0, messagesSent: overallStats.messagesSent || 0, totalMessageStarted: overallStats.totalMessageStarted || 0, totalMessageReplies: overallStats.totalMessageReplies || 0, inmailMessagesSent: overallStats.inmailMessagesSent || 0, totalInmailStarted: overallStats.totalInmailStarted || 0, totalInmailReplies: overallStats.totalInmailReplies || 0, connectionAcceptanceRate: overallStats.connectionAcceptanceRate ? (overallStats.connectionAcceptanceRate * 100).toFixed(2) : '0.00', messageReplyRate: overallStats.messageReplyRate ? (overallStats.messageReplyRate * 100).toFixed(2) : '0.00', totalLeads: campaignConfig.progressStats.totalUsers, leadsFinished: campaignConfig.progressStats.totalUsersFinished, leadsFailed: campaignConfig.progressStats.totalUsersFailed, leadsInProgress: campaignConfig.progressStats.totalUsersInProgress, leadsPending: campaignConfig.progressStats.totalUsersPending, leadsExcluded: campaignConfig.progressStats.totalUsersExcluded };

const campaignAccountIds = campaignConfig.senderAccountIds;
const accountsAnalysis = { totalAccountsInCampaign: campaignAccountIds.length, accounts: [], activeCount: 0 };
accountsData.forEach(account => {
  if (campaignAccountIds.includes(account.id)) {
    if (account.isActive === true) accountsAnalysis.activeCount++;
    accountsAnalysis.accounts.push({ id: account.id, name: `${account.firstName || ''} ${account.lastName || ''}`.trim(), email: account.emailAddress, isActive: account.isActive, authIsValid: account.authIsValid });
  }
});

const sentimentKeywords = { positive: ['interested','yes','sure','love to','sounds good','happy to','schedule','call','meeting','tell me more','send more','great','perfect','excited','looking forward','thanks for reaching','keep me posted','next one'], negative: ['not interested','no thanks','no thank you','remove','stop','unsubscribe','spam','wrong person'], neutral: ['not now','bad timing','busy','maybe later','check back','next quarter'] };
function classifySentiment(text) {
  if (!text) return 'informational';
  const l = text.toLowerCase();
  for (const k of sentimentKeywords.positive) if (l.includes(k)) return 'positive';
  for (const k of sentimentKeywords.negative) if (l.includes(k)) return 'negative';
  for (const k of sentimentKeywords.neutral) if (l.includes(k)) return 'neutral';
  return 'informational';
}

const windowStartTs = requestContext.startDate ? new Date(requestContext.startDate).getTime() : 0;
const windowEndTs = requestContext.endDate ? new Date(requestContext.endDate).getTime() + 86400000 : Infinity;
const replyAnalysis = { totalConversations: inboxData.length, conversationsWithReplies: 0, totalReplies: 0, replies: [], sentimentBreakdown: { positive: [], neutral: [], negative: [], informational: [] } };
const leadsAnalysis = { totalLeads: analytics.totalLeads, byJobTitle: {}, byCompany: {}, connectedLeads: [], repliedLeads: [] };
let uniqueProspectsMeassaged = 0;

inboxData.forEach(conversation => {
  const profile = conversation.correspondentProfile || {};
  const messages = conversation.messages || [];
  const hasOutboundInWindow = messages.some(m => { if (m.sender !== 'ME') return false; const ts = new Date(m.createdAt || m.timestamp || 0).getTime(); return ts >= windowStartTs && ts <= windowEndTs; });
  if (hasOutboundInWindow) uniqueProspectsMeassaged++;
  const leadInfo = { name: `${profile.firstName || ''} ${profile.lastName || ''}`.trim(), company: profile.companyName || '', position: profile.position || profile.headline || '', location: profile.location || '', linkedInUrl: profile.profileUrl || '' };
  if (leadInfo.company) leadsAnalysis.byCompany[leadInfo.company] = (leadsAnalysis.byCompany[leadInfo.company] || 0) + 1;
  const correspondentReplies = messages.filter(m => m.sender === 'CORRESPONDENT');
  const windowReplies = correspondentReplies.filter(m => { const ts = new Date(m.createdAt || m.timestamp || 0).getTime(); return ts >= windowStartTs && ts <= windowEndTs; });
  if (windowReplies.length > 0) {
    replyAnalysis.conversationsWithReplies++;
    replyAnalysis.totalReplies += 1;
    windowReplies.forEach(reply => {
      const replyText = reply.body || '';
      const sentiment = classifySentiment(replyText);
      const replyRecord = { from: leadInfo.name, company: leadInfo.company, position: leadInfo.position, location: leadInfo.location, linkedInUrl: leadInfo.linkedInUrl, replyText: replyText, replyPreview: replyText.length > 300 ? replyText.substring(0, 300) + '...' : replyText, timestamp: reply.createdAt, sentiment };
      replyAnalysis.replies.push(replyRecord);
      leadsAnalysis.repliedLeads.push(leadInfo);
      replyAnalysis.sentimentBreakdown[sentiment].push(replyRecord);
    });
  }
  leadsAnalysis.connectedLeads.push(leadInfo);
});
analytics.messagesSent = uniqueProspectsMeassaged;

const totalRepliesForSentiment = replyAnalysis.totalReplies || 1;
replyAnalysis.sentimentSummary = { positive: { count: replyAnalysis.sentimentBreakdown.positive.length }, neutral: { count: replyAnalysis.sentimentBreakdown.neutral.length }, negative: { count: replyAnalysis.sentimentBreakdown.negative.length }, informational: { count: replyAnalysis.sentimentBreakdown.informational.length } };

const reportData = { requestContext, platformType: 'linkedin', campaignConfig, analytics, leadsAnalysis: { totalLeads: leadsAnalysis.totalLeads, connectedCount: leadsAnalysis.connectedLeads.length, repliedCount: leadsAnalysis.repliedLeads.length, repliedLeads: leadsAnalysis.repliedLeads }, replyAnalysis, accountsAnalysis, generatedAt: new Date().toISOString() };

  results.push({ json: { reportData, reportDataString: JSON.stringify(reportData, null, 2) } });
}

return results;

// Parse structured JSON output from Instantly AI Agent — one item per campaign
const config = $('Workflow Configuration').first().json;
const allItems = $input.all();
const matchItems = $('Match Instantly Campaign Name - Exist or not').all()
  .filter(item => item.json.matched === true);

const results = [];
for (let i = 0; i < allItems.length; i++) {
  const raw = allItems[i].json.output || allItems[i].json.text || '';
  let parsed = {};
  try {
    const match = raw.match(/\{[\s\S]*\}/);
    if (match) { parsed = JSON.parse(match[0]); }
    else { parsed = { error: 'No JSON found in AI output', rawPreview: raw.slice(0, 300) }; }
  } catch (e) { parsed = { error: e.message, rawPreview: raw.slice(0, 300) }; }

  const targetCampaignName = matchItems[i]?.json.targetCampaignName || parsed.campaignName || `Campaign ${i + 1}`;

  results.push({
    json: {
      instantlyData: { ...parsed, targetCampaignName, platform: 'instantly' },
      targetCampaignName,
      clientName: config.clientName,
      startDate: config.startDate,
      endDate: config.endDate
    }
  });
}
return results;

// Parse structured JSON output from HeyReach AI Agent — one item per campaign
const config = $('Workflow Configuration').first().json;
const allItems = $input.all();
const matchItems = $('Match Heyreach Campaign Name - Exist or not').all()
  .filter(item => item.json.matched === true);

const results = [];
for (let i = 0; i < allItems.length; i++) {
  const raw = allItems[i].json.output || allItems[i].json.text || '';
  let parsed = {};
  try {
    const match = raw.match(/\{[\s\S]*\}/);
    if (match) { parsed = JSON.parse(match[0]); }
    else { parsed = { error: 'No JSON found in AI output', rawPreview: raw.slice(0, 300) }; }
  } catch (e) { parsed = { error: e.message, rawPreview: raw.slice(0, 300) }; }

  const targetCampaignName = matchItems[i]?.json.targetCampaignName || parsed.campaignName || `Campaign ${i + 1}`;

  results.push({
    json: {
      heyreachData: { ...parsed, targetCampaignName, platform: 'heyreach' },
      targetCampaignName,
      clientName: config.clientName,
      startDate: config.startDate,
      endDate: config.endDate
    }
  });
}
return results;

// ============================================================
// COMPOSE COMBINED REPORT — Dynamic Multi-Campaign v5
// Aligned with FullFunnel Prompt Formatting Spec
// ============================================================
const items = $input.all();
const config = $('Workflow Configuration').first().json;

const clientName = config.clientName || 'Unknown Client';
const startDate = config.startDate || '';
const endDate = config.endDate || '';
const campaignContext = config.campaignContext || '';

const instantlyCampaignNames = Array.isArray(config.instantlyCampaignNames) ? config.instantlyCampaignNames : [];
const heyReachCampaignNames = Array.isArray(config.heyReachCampaignNames) ? config.heyReachCampaignNames : [];

const instantlyItems = [];
const heyreachItems = [];
const instantlyLifetimeItems = [];
const heyreachLifetimeItems = [];

for (const item of items) {
  const d = item.json || {};
  if (d.instantlyData && typeof d.instantlyData === 'object' && !d.instantlyData.error) {
    instantlyItems.push(d.instantlyData);
  }
  if (d.heyreachData && typeof d.heyreachData === 'object' && !d.heyreachData.error) {
    heyreachItems.push(d.heyreachData);
  }
  if (d.instantlyLifetimeData) {
    try { instantlyLifetimeItems.push(JSON.parse(d.instantlyLifetimeData)); } catch(e) {}
  }
  if (d.heyreachLifetimeData) {
    try { heyreachLifetimeItems.push(JSON.parse(d.heyreachLifetimeData)); } catch(e) {}
  }
}

const norm = s => (s || '').toLowerCase().replace(/[^a-z0-9]/g, '');
const sortByOrder = (arr, nameList) => {
  return [...arr].sort((a, b) => {
    const nameA = a.targetCampaignName || a.campaignName || '';
    const nameB = b.targetCampaignName || b.campaignName || '';
    const findIdx = (name, list) => {
      const nName = norm(name);
      let idx = list.findIndex(n => norm(n) === nName);
      if (idx === -1) idx = list.findIndex(n => nName.includes(norm(n)) || norm(n).includes(nName));
      return idx === -1 ? 999 : idx;
    };
    return findIdx(nameA, nameList) - findIdx(nameB, nameList);
  });
};

const sortedInstantly = sortByOrder(instantlyItems, instantlyCampaignNames);
const sortedHeyreach = sortByOrder(heyreachItems, heyReachCampaignNames);

// ── Renderers ────────────────────────────────────────────────

// Section 2: Campaign Overview
// Instantly: no Platform field, no duplicate campaign name
const renderInstantlyOverview = (d) => {
  if (!d) return '';
  const o = d.campaignOverview || {};
  return [
    'Status: ' + (o.status || 'Unknown'),
    'Reporting Window: ' + (o.reportingWindow || startDate + ' to ' + endDate),
    'Sender Accounts: ' + (o.senderAccounts || 'N/A')
  ].join('\n');
};

// HeyReach: keep Platform field, no duplicate campaign name
const renderHeyreachOverview = (d) => {
  if (!d) return '';
  const o = d.campaignOverview || {};
  return [
    'Platform: LinkedIn (HeyReach)',
    'Status: ' + (o.status || 'Unknown'),
    'Reporting Window: ' + (o.reportingWindow || startDate + ' to ' + endDate),
    'Sender Accounts: ' + (o.senderAccounts || 'N/A')
  ].join('\n');
};

// Section 3: Scorecard
const renderInstantlyScorecard = (d) => {
  if (!d) return '';
  const s = d.performanceScorecard || {};
  return [
    'Emails Sent: ' + (s.emailsSent ?? 'N/A'),
    'Unique Leads Contacted: ' + (s.uniqueLeadsContacted ?? 'N/A'),
    'Reply Rate: ' + (s.replyRate ?? 'N/A'),
    'Bounce Rate: ' + (s.bounceRate ?? 'N/A'),
    'Open Rate: ' + (s.openRate ?? 'N/A'),
    'Auto-Reply Rate: ' + (s.autoReplyRate ?? 'N/A'),
    'Emails Per Lead: ' + (s.emailsPerLead ?? 'N/A')
  ].join('\n');
};

// HeyReach: simplified 7-field scorecard per updated spec
const renderHeyreachScorecard = (d) => {
  if (!d) return '';
  const s = d.performanceScorecard || {};
  return [
    'Connection Requests Sent: ' + (s.connectionRequestsSent ?? 'N/A'),
    'Connections Accepted: ' + (s.connectionsAccepted ?? 'N/A'),
    'Connection Acceptance Rate: ' + (s.connectionAcceptanceRate ?? 'N/A'),
    'Messages Sent: ' + (s.messagesSent ?? 'N/A'),
    'Message Replies: ' + (s.messageReplies ?? 'N/A'),
    'Message Reply Rate: ' + (s.messageReplyRate ?? 'N/A'),
    'Failure Rate: ' + (s.failureRate ?? 'N/A')
  ].join('\n');
};

// Section 4: Reply Highlights
// Only show detail if hasReplies = true, otherwise single line only
const renderReplies = (rh, isInstantly) => {
  const noReplyMsg = isInstantly
    ? 'No human replies received during this reporting window.'
    : 'No replies received during this reporting window.';

  if (!rh || !rh.hasReplies) return noReplyMsg;

  const lines = [];
  const replies = rh.replies || [];

  if (isInstantly) {
    lines.push('Total Replies Received: ' + (rh.totalReplies ?? 0));
    lines.push('Human Replies: ' + (rh.humanReplies ?? 0));
  } else {
    lines.push('Conversations With Replies: ' + (rh.conversationsWithReplies ?? 0));
  }

  if (rh.sentimentBreakdown) {
    lines.push('Sentiment Breakdown: ' + rh.sentimentBreakdown);
  }

  if (replies.length > 0) {
    lines.push('');
    replies.forEach(r => {
      lines.push('[' + (r.sentiment || 'Unknown').toUpperCase() + '] ' + (r.name || '') + ', ' + (r.title || '') + ' @ ' + (r.company || ''));
      lines.push('"' + (r.text || '') + '"');
      lines.push('');
    });
  }

  return lines.join('\n').trim();
};

// Section 5: Key Insights
const renderKeyInsights = (d) => {
  if (!d) return '';
  const ki = d.keyInsights || {};
  const lines = [];
  if (ki.verdict) lines.push('Performance Verdict: ' + ki.verdict);
  if (ki.primarySignal) lines.push('Primary Signal: ' + ki.primarySignal);
  if (ki.whatsWorking && ki.whatsWorking.length) {
    lines.push("What's Working:");
    ki.whatsWorking.forEach(b => lines.push('• ' + b));
  }
  if (ki.areasToWatch && ki.areasToWatch.length) {
    lines.push('Areas to Watch:');
    ki.areasToWatch.forEach(b => lines.push('• ' + b));
  }
  return lines.join('\n');
};


// Lifetime renderers
const renderInstantlyLifetime = (d) => {
  if (!d) return '';
  const sent = d.emails_sent_count || 0;
  const pct = (n) => sent > 0 ? ((n / sent) * 100).toFixed(2) + '%' : '0.00%';
  const lines = [
    'Emails Sent: ' + (sent || 'N/A'),
    'Unique Leads Contacted: ' + (d.leads_count ?? 'N/A'),
    'Unique Replies: ' + (d.reply_count_unique ?? 'N/A'),
    'Reply Rate: ' + pct(d.reply_count_unique || 0),
    'Bounces: ' + (d.bounced_count ?? 'N/A'),
    'Bounce Rate: ' + pct(d.bounced_count || 0),
    'Auto-Replies: ' + (d.reply_count_automatic ?? 'N/A'),
    'Auto-Reply Rate: ' + pct(d.reply_count_automatic || 0)
  ];
  if (d.open_count_unique > 0) {
    lines.push('Unique Opens: ' + d.open_count_unique);
    lines.push('Open Rate: ' + pct(d.open_count_unique));
  } else {
    lines.push('Open Rate: Not tracked — open tracking disabled');
  }
  return lines.join('\n');
};

const renderHeyreachLifetime = (d) => {
  if (!d) return '';
  const os = d.overallStats || {};
  const pct = (n) => n != null ? (parseFloat(n) * 100).toFixed(2) + '%' : 'N/A';
  const lines = [
    'Connection Requests Sent: ' + (os.connectionsSent ?? 'N/A'),
    'Connections Accepted: ' + (os.connectionsAccepted ?? 'N/A'),
    'Connection Acceptance Rate: ' + pct(os.connectionAcceptanceRate),
    'Messages Sent: ' + (os.messagesSent ?? 'N/A'),
    'Message Replies: ' + (os.totalMessageReplies ?? 'N/A'),
    'Message Reply Rate: ' + pct(os.messageReplyRate),
    'Profile Views: ' + (os.profileViews ?? 'N/A')
  ];
  if (os.inmailMessagesSent) {
    lines.push('InMail Sent: ' + os.inmailMessagesSent);
    lines.push('InMail Replies: ' + (os.totalInmailReplies ?? 'N/A'));
  }
  return lines.join('\n');
};

// ── Build Document ────────────────────────────────────────────
const doc = [];
const DIV = '═══════════════════════════════════════';
const SUB = '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━';

// Header
doc.push(clientName + ' // Combined Outbound Report');
doc.push('Client: ' + clientName);
doc.push('Date Range: ' + startDate + ' to ' + endDate);
doc.push('');
doc.push('Instantly Campaigns:');
sortedInstantly.forEach(c => doc.push('• ' + (c.targetCampaignName || c.campaignName || '')));
doc.push('');
doc.push('HeyReach Campaigns:');
sortedHeyreach.forEach(c => doc.push('• ' + (c.targetCampaignName || c.campaignName || '')));
doc.push('');
doc.push(DIV);

// SECTION 1: EXECUTIVE SUMMARY
doc.push('SECTION 1: EXECUTIVE SUMMARY');
doc.push(DIV);
doc.push('');
doc.push('INSTANTLY');
doc.push(SUB);
for (const d of sortedInstantly) {
  doc.push(d.targetCampaignName || d.campaignName || '');
  doc.push(d.executiveSummary || '');
  doc.push('');
}
doc.push('HEYREACH');
doc.push(SUB);
for (const d of sortedHeyreach) {
  doc.push(d.targetCampaignName || d.campaignName || '');
  doc.push(d.executiveSummary || '');
  doc.push('');
}
doc.push(DIV);

// SECTION 2: CAMPAIGN OVERVIEW
doc.push('SECTION 2: CAMPAIGN OVERVIEW');
doc.push(DIV);
doc.push('');
doc.push('INSTANTLY');
doc.push(SUB);
for (const d of sortedInstantly) {
  doc.push(d.targetCampaignName || d.campaignName || '');
  doc.push(renderInstantlyOverview(d));
  doc.push('');
}
doc.push('HEYREACH');
doc.push(SUB);
for (const d of sortedHeyreach) {
  doc.push(d.targetCampaignName || d.campaignName || '');
  doc.push(renderHeyreachOverview(d));
  doc.push('');
}
doc.push(DIV);

// SECTION 3: PERFORMANCE SCORECARD
doc.push('SECTION 3: PERFORMANCE SCORECARD');
doc.push(DIV);
doc.push('');
doc.push('INSTANTLY');
doc.push(SUB);
for (const d of sortedInstantly) {
  doc.push(d.targetCampaignName || d.campaignName || '');
  doc.push(renderInstantlyScorecard(d));
  doc.push('');
}
doc.push('HEYREACH');
doc.push(SUB);
for (const d of sortedHeyreach) {
  doc.push(d.targetCampaignName || d.campaignName || '');
  doc.push(renderHeyreachScorecard(d));
  doc.push('');
}
doc.push(DIV);

// SECTION 4: REPLY HIGHLIGHTS
doc.push('SECTION 4: REPLY HIGHLIGHTS');
doc.push(DIV);
doc.push('');
doc.push('INSTANTLY');
doc.push(SUB);
for (const d of sortedInstantly) {
  doc.push(d.targetCampaignName || d.campaignName || '');
  doc.push(renderReplies(d.replyHighlights, true));
  doc.push('');
}
doc.push('HEYREACH');
doc.push(SUB);
for (const d of sortedHeyreach) {
  doc.push(d.targetCampaignName || d.campaignName || '');
  doc.push(renderReplies(d.replyHighlights, false));
  doc.push('');
}
doc.push(DIV);

// SECTION 5: KEY INSIGHTS
doc.push('SECTION 5: KEY INSIGHTS');
doc.push(DIV);
doc.push('');
doc.push('INSTANTLY');
doc.push(SUB);
for (const d of sortedInstantly) {
  doc.push(d.targetCampaignName || d.campaignName || '');
  doc.push(renderKeyInsights(d));
  doc.push('');
}
doc.push('HEYREACH');
doc.push(SUB);
for (const d of sortedHeyreach) {
  doc.push(d.targetCampaignName || d.campaignName || '');
  doc.push(renderKeyInsights(d));
  doc.push('');
}
doc.push(DIV);

// SECTION 6: RECOMMENDATIONS (blank — filled by MDs)
doc.push('SECTION 6: RECOMMENDATIONS');
doc.push(DIV);
doc.push('Leave this section blank. Recommendations are provided by the account team.');
doc.push('');
doc.push(DIV);

// SECTION 7: LIFETIME CAMPAIGN ANALYTICS
doc.push('SECTION 7: LIFETIME CAMPAIGN ANALYTICS');
doc.push(DIV);
doc.push('');
doc.push('INSTANTLY (Lifetime — campaign creation to today)');
doc.push(SUB);
if (instantlyLifetimeItems.length === 0) {
  doc.push('No lifetime data available.');
  doc.push('');
} else {
  for (const d of instantlyLifetimeItems) {
    doc.push(d.campaign_name || 'Unknown Campaign');
    doc.push(renderInstantlyLifetime(d));
    doc.push('');
  }
}
doc.push('HEYREACH (Lifetime — campaign creation to today)');
doc.push(SUB);
if (heyreachLifetimeItems.length === 0) {
  doc.push('No lifetime data available.');
  doc.push('');
} else {
  for (const d of heyreachLifetimeItems) {
    doc.push(d.campaign_name || d.name || 'Unknown Campaign');
    doc.push(renderHeyreachLifetime(d));
    doc.push('');
  }
}
doc.push(DIV);

// COMBINED READOUT
doc.push('COMBINED READOUT');
doc.push('');
doc.push('{{COMBINED_READOUT}}');
doc.push('');
doc.push('--- END OF DOCUMENT ---');

const documentText = doc.join('\n');

const campaignSummaries = [
  ...sortedInstantly.map(d => ({
    platform: 'Instantly',
    label: d.targetCampaignName || d.campaignName || '',
    verdict: d.keyInsights ? d.keyInsights.verdict || null : null,
    summary: d.executiveSummary || null,
    topSignals: d.replyHighlights ? (d.replyHighlights.sentimentBreakdown || null) : null
  })),
  ...sortedHeyreach.map(d => ({
    platform: 'HeyReach',
    label: d.targetCampaignName || d.campaignName || '',
    verdict: d.keyInsights ? d.keyInsights.verdict || null : null,
    summary: d.executiveSummary || null,
    topSignals: d.replyHighlights ? (d.replyHighlights.sentimentBreakdown || null) : null
  }))
];

const instantlyCampaignName = sortedInstantly.map(c => c.targetCampaignName || c.campaignName || '').filter(Boolean).join(', ') || '(none)';
const heyreachCampaignName = sortedHeyreach.map(c => c.targetCampaignName || c.campaignName || '').filter(Boolean).join(', ') || '(none)';

return [{ json: { documentText, campaignSummaries, clientName, startDate, endDate, campaignContext, instantlyCampaignName, heyreachCampaignName } }];

